  post_content = '<!-- wp:divi/placeholder -->\n<!-- wp:html --><style>/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === LEGAL PAGE: THAI PRIVACY POLICY === */\n/* Divi section-level overrides for legal pages */\n.et_pb_section { padding: 0 !important; min-height: auto !important; margin: 0 !important; text-align: start !important; }\n.et_pb_section .et_pb_row { max-width: 100% !important; width: 100% !important; padding: 0 !important; margin: 0 auto !important; }\n.et_pb_section .et_pb_column { padding: 0 !important; }\n.et_pb_section, .et_pb_section * { -webkit-font-smoothing: auto !important; -moz-osx-font-smoothing: auto !important; }\n.et_pb_section p { padding-bottom: 0 !important; }\n.fade-in { opacity: 1 !important; transform: none !important; }\n:root { --dw-blue-text: #0369a1; --dw-gray-light: #F5F7FA; --dw-navy: #000864; }\n\n/* Thai font override for legal content */\n.dw-section, .dw-section * {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n}\n.dw-section h1, .dw-section h2 {\n  line-height: 1.4 !important;\n}\n.dw-section p, .dw-section li {\n  line-height: 1.8 !important;\n}\n\n/* === THAI TYPOGRAPHY === */\n/* Font loaded via <link> in header — do NOT use @import here (invalid after rules) */\n\n/* Thai font stack for all body text */\nbody, .et_pb_section, .et_pb_code, .et_pb_code_inner {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n}\n\n/* Thai-specific line heights (Thai script is taller — needs !important to override Divi) */\np, li, .et_pb_text_inner { line-height: 1.8 !important; }\nh1, h2, h3, h4, h5, h6 { line-height: 1.4 !important; }\n\n/* Thai label override: JetBrains Mono doesn\'t have Thai glyphs.\n   letter-spacing breaks Thai script (chars within words must stay connected).\n   text-transform:uppercase is meaningless for Thai. */\n[class*="-label"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n/* Also fix any monospace elements that might contain Thai text */\n[class*="-source"], [class*="-company"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"นโยบายความเป็นส่วนตัว: Content"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"นโยบายความเป็นส่วนตัว: Content: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"นโยบายความเป็นส่วนตัว: Content: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><section class="dw-section" style="padding-top: 120px;">\n  <div class="dw-container">\n    <div style="max-width: 800px; margin: 0 auto;">\n      <h1 style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 36px; color: #000864; margin-bottom: 16px;">นโยบายความเป็นส่วนตัว</h1>\n      <p style="color: #5b6b80; margin-bottom: 48px;">อัปเดตล่าสุด: กุมภาพันธ์ 2569</p>\n\n      <div style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 16px; line-height: 1.8; color: #000864;">\n        <h2 style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 24px; margin: 32px 0 16px 0;">1. ข้อมูลที่เราเก็บรวบรวม</h2>\n        <p>DigiWin Thailand ("เรา" หรือ "บริษัท") เก็บรวบรวมข้อมูลที่ท่านให้โดยตรง เช่น เมื่อท่านติดต่อเรา สอบถามข้อมูล หรือสมัครเป็นพันธมิตรทางธุรกิจ ข้อมูลดังกล่าวอาจรวมถึง:</p>\n        <ul style="margin: 16px 0; padding-left: 24px;">\n          <li>ชื่อและข้อมูลติดต่อ</li>\n          <li>ชื่อบริษัทและตำแหน่งงาน</li>\n          <li>ที่อยู่อีเมลและหมายเลขโทรศัพท์</li>\n          <li>ข้อมูลเกี่ยวกับการดำเนินงานด้านการผลิตของท่าน</li>\n        </ul>\n\n        <h2 style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 24px; margin: 32px 0 16px 0;">2. วิธีการใช้ข้อมูลของท่าน</h2>\n        <p>เราใช้ข้อมูลที่เก็บรวบรวมเพื่อ:</p>\n        <ul style="margin: 16px 0; padding-left: 24px;">\n          <li>ตอบข้อซักถามและคำขอของท่าน</li>\n          <li>ให้ข้อมูลเกี่ยวกับผลิตภัณฑ์และบริการของเรา</li>\n          <li>ดำเนินการพิจารณาใบสมัครพันธมิตรทางธุรกิจ</li>\n          <li>ปรับปรุงเว็บไซต์และบริการของเรา</li>\n          <li>ส่งข้อมูลด้านการตลาด (โดยได้รับความยินยอมจากท่าน)</li>\n        </ul>\n\n        <h2 style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 24px; margin: 32px 0 16px 0;">3. การเปิดเผยข้อมูล</h2>\n        <p>เราไม่ขาย แลกเปลี่ยน หรือให้เช่าข้อมูลส่วนบุคคลของท่านแก่บุคคลภายนอก เราอาจเปิดเผยข้อมูลของท่านแก่:</p>\n        <ul style="margin: 16px 0; padding-left: 24px;">\n          <li>บริษัทในกลุ่ม DigiWin เพื่อวัตถุประสงค์ทางธุรกิจ</li>\n          <li>ผู้ให้บริการที่ช่วยสนับสนุนการดำเนินงานของเรา</li>\n          <li>หน่วยงานทางกฎหมายเมื่อกฎหมายกำหนด</li>\n        </ul>\n\n        <h2 style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 24px; margin: 32px 0 16px 0;">4. ความปลอดภัยของข้อมูล</h2>\n        <p>เราใช้มาตรการทางเทคนิคและองค์กรที่เหมาะสมเพื่อปกป้องข้อมูลส่วนบุคคลของท่านจากการเข้าถึง เปลี่ยนแปลง เปิดเผย หรือทำลายโดยไม่ได้รับอนุญาต</p>\n\n        <h2 style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 24px; margin: 32px 0 16px 0;">5. สิทธิของท่าน</h2>\n        <p>ภายใต้พระราชบัญญัติคุ้มครองข้อมูลส่วนบุคคล (PDPA) ของประเทศไทย ท่านมีสิทธิ:</p>\n        <ul style="margin: 16px 0; padding-left: 24px;">\n          <li>เข้าถึงข้อมูลส่วนบุคคลของท่าน</li>\n          <li>แก้ไขข้อมูลที่ไม่ถูกต้อง</li>\n          <li>ขอลบข้อมูลของท่าน</li>\n          <li>เพิกถอนความยินยอม</li>\n          <li>ยื่นเรื่องร้องเรียนต่อหน่วยงานที่เกี่ยวข้อง</li>\n        </ul>\n\n        <h2 style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 24px; margin: 32px 0 16px 0;">6. ติดต่อเรา</h2>\n        <p>หากท่านมีข้อสงสัยเกี่ยวกับนโยบายความเป็นส่วนตัวนี้ หรือต้องการใช้สิทธิของท่าน กรุณาติดต่อเราที่:</p>\n        <p style="margin-top: 16px;">\n          <strong>DigiWin Thailand</strong><br>\n          อีเมล: <a href="mailto:info@digiwin.co.th" style="color: #0369a1;">info@digiwin.co.th</a>\n        </p>\n      </div>\n    </div>\n  </div>\n</section><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
  post_modified = NOW(),
  post_modified_gmt = UTC_TIMESTAMP()
WHERE ID = 100795;

